import{c as a,Q as t,j as i,m as e}from"./chunks/framework.Bhbi9jCp.js";const c=JSON.parse('{"title":"播放器原理与缓冲策略","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/12-播放器原理与缓冲策略.md","filePath":"mediaTechLearning/12-播放器原理与缓冲策略.md","lastUpdated":1780887690000}'),n={name:"mediaTechLearning/12-播放器原理与缓冲策略.md"};function l(p,s,d,h,r,o){return t(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="播放器原理与缓冲策略" tabindex="-1">播放器原理与缓冲策略 <a class="header-anchor" href="#播放器原理与缓冲策略" aria-label="Permalink to &quot;播放器原理与缓冲策略&quot;">​</a></h1><p>播放器不是简单 <code>&lt;video src&gt;</code>。它要拉数据、解封装、解码、同步音画、管理缓冲,还要在弱网下做取舍。</p><blockquote><p>一句话先记住:<strong>播放器的核心工作是让解码后的音视频帧按时间稳定输出</strong>。缓冲太少会卡,缓冲太多会慢。</p></blockquote><hr><h2 id="一、播放器管线" tabindex="-1">一、播放器管线 <a class="header-anchor" href="#一、播放器管线" aria-label="Permalink to &quot;一、播放器管线&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>网络拉取</span></span>
<span class="line"><span>  -&gt; demux 解封装</span></span>
<span class="line"><span>  -&gt; decode 解码</span></span>
<span class="line"><span>  -&gt; audio/video queue</span></span>
<span class="line"><span>  -&gt; clock 同步</span></span>
<span class="line"><span>  -&gt; render 输出</span></span></code></pre></div><p>浏览器里很多细节由内核和硬件解码器处理,但业务仍要关注:</p><ul><li>首帧时间</li><li>缓冲长度</li><li>卡顿次数</li><li>清晰度切换</li><li>错误码</li></ul><hr><h2 id="二、缓冲是什么" tabindex="-1">二、缓冲是什么 <a class="header-anchor" href="#二、缓冲是什么" aria-label="Permalink to &quot;二、缓冲是什么&quot;">​</a></h2><p>缓冲就是提前准备的可播放数据:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前播放点: 10s</span></span>
<span class="line"><span>已缓冲到:   25s</span></span>
<span class="line"><span>缓冲长度:   15s</span></span></code></pre></div><p>HTMLVideoElement 可以看:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> video</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> document.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">querySelector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;video&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> video.buffered.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(video.buffered.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">start</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(i), video.buffered.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">end</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(i))</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><hr><h2 id="三、首帧、卡顿、延迟是三角" tabindex="-1">三、首帧、卡顿、延迟是三角 <a class="header-anchor" href="#三、首帧、卡顿、延迟是三角" aria-label="Permalink to &quot;三、首帧、卡顿、延迟是三角&quot;">​</a></h2><table tabindex="0"><thead><tr><th>目标</th><th>策略</th><th>代价</th></tr></thead><tbody><tr><td>首帧快</td><td>少缓冲就播</td><td>弱网容易卡</td></tr><tr><td>少卡顿</td><td>多缓冲</td><td>首帧慢 / 直播延迟高</td></tr><tr><td>低延迟</td><td>追直播边缘</td><td>更容易卡</td></tr></tbody></table><p>点播可以多缓冲。会议不能多缓冲。直播在中间取舍。</p><hr><h2 id="四、abr-切换" tabindex="-1">四、ABR 切换 <a class="header-anchor" href="#四、abr-切换" aria-label="Permalink to &quot;四、ABR 切换&quot;">​</a></h2><p>自适应码率播放器会根据:</p><ul><li>估算带宽</li><li>当前缓冲</li><li>下载速度</li><li>设备解码能力</li><li>历史卡顿</li></ul><p>选择下一片清晰度。切换不是立刻换当前画面,通常从下一片开始。</p><blockquote><p>ABR 不是选最高码率,而是在不卡顿的前提下尽量高清。</p></blockquote><hr><h2 id="五、mse-播放器" tabindex="-1">五、MSE 播放器 <a class="header-anchor" href="#五、mse-播放器" aria-label="Permalink to &quot;五、MSE 播放器&quot;">​</a></h2><p>浏览器原生 <code>&lt;video&gt;</code> 不一定直接支持 FLV / DASH / 自定义切片。MSE(Media Source Extensions)允许 JS 往播放器喂媒体片段:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fetch segment</span></span>
<span class="line"><span>  -&gt; appendBuffer</span></span>
<span class="line"><span>  -&gt; SourceBuffer</span></span>
<span class="line"><span>  -&gt; video element</span></span></code></pre></div><p>hls.js、dash.js、flv.js 这类播放器都建立在 MSE 能力上。</p><hr><h2 id="六、关键指标" tabindex="-1">六、关键指标 <a class="header-anchor" href="#六、关键指标" aria-label="Permalink to &quot;六、关键指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>意义</th></tr></thead><tbody><tr><td>startup time</td><td>点击播放到首帧</td></tr><tr><td>rebuffer count</td><td>卡顿次数</td></tr><tr><td>rebuffer duration</td><td>卡顿总时长</td></tr><tr><td>bitrate</td><td>当前码率</td></tr><tr><td>dropped frames</td><td>丢帧</td></tr><tr><td>live latency</td><td>直播落后真实时间</td></tr></tbody></table><p>没有这些指标,播放器线上问题只能靠用户截图。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>只看能不能播</strong>——生产要看首帧和卡顿。</li><li><strong>直播缓冲越大越稳</strong>——稳是稳,但延迟会失控。</li><li><strong>播放器错误不打点</strong>——线上排障没证据。</li><li><strong>切清晰度不对齐关键帧</strong>——容易花屏或卡。</li><li><strong>忽略硬件解码能力</strong>——低端机播 4K 会掉帧。</li></ol><p>下一篇:<code>13-浏览器 Media API.md</code>。</p>`,37)])])}const g=a(n,[["render",l]]);export{c as __pageData,g as default};
